import XCTest
@testable import Runout

/// Fixtures below are real, unmodified responses captured live from musicbrainz.org (search for
/// "The Beatles" / "Abbey Road", and the full release detail for the original 1969 GB pressing,
/// MBID 05e77dbd-1c4f-4e5e-8461-caac6e5fbae7) — so parsing is verified against genuine API
/// output, not a hypothetical shape.
final class MusicBrainzClientTests: XCTestCase {
    func testParsesRealSearchResults() throws {
        let results = try MusicBrainzClient.parseSearchResults(Self.realSearchResponseJSON)

        XCTAssertEqual(results.count, 2)
        XCTAssertEqual(results[0].id, "ed787f95-6668-4767-889c-0e4a720c739f")
        XCTAssertEqual(results[0].title, "Abbey Road")
        XCTAssertEqual(results[0].artist, "The Beatles")
        XCTAssertEqual(results[0].date, "1970")
        XCTAssertEqual(results[0].country, "GB")
        XCTAssertEqual(results[0].trackCount, 17)

        XCTAssertEqual(results[1].country, "US")
        XCTAssertEqual(results[1].date, "1980-01")
    }

    func testParsesRealReleaseDetailWithFullTrackListing() throws {
        let detail = try MusicBrainzClient.parseReleaseDetail(Self.realReleaseDetailJSON)

        XCTAssertEqual(detail.title, "Abbey Road")
        XCTAssertEqual(detail.artist, "The Beatles")
        XCTAssertEqual(detail.date, "1969-09-26")
        XCTAssertTrue(detail.hasCoverArt)
        XCTAssertEqual(detail.tracks.count, 17)
        XCTAssertEqual(detail.tracks[0], MusicBrainzTrack(position: 1, title: "Come Together"))
        XCTAssertEqual(detail.tracks[1], MusicBrainzTrack(position: 2, title: "Something"))
        XCTAssertEqual(detail.tracks[16], MusicBrainzTrack(position: 17, title: "Her Majesty"))
        // Curly apostrophe (’), not straight — confirms real Unicode content decodes correctly.
        XCTAssertEqual(detail.tracks[2].title, "Maxwell\u{2019}s Silver Hammer")
    }

    /// docs/IMPROVEMENT_PLAN.md P3: an unescaped Lucene special character in the search text
    /// (quotes, colons, etc.) breaks the query instead of matching literally.
    func testEscapeForLuceneQueryEscapesSpecialCharacters() {
        XCTAssertEqual(MusicBrainzClient.escapeForLuceneQuery("\"Heroes\""), "\\\"Heroes\\\"")
        XCTAssertEqual(MusicBrainzClient.escapeForLuceneQuery("Rock: The Album"), "Rock\\: The Album")
        XCTAssertEqual(MusicBrainzClient.escapeForLuceneQuery("AC/DC"), "AC\\/DC")
        XCTAssertEqual(MusicBrainzClient.escapeForLuceneQuery("Simon & Garfunkel"), "Simon \\& Garfunkel")
        XCTAssertEqual(MusicBrainzClient.escapeForLuceneQuery("Plain Text"), "Plain Text", "text with nothing special must pass through unchanged")
    }

    func testParsingGarbageThrowsDecodingFailed() {
        let garbage = Data("not json at all".utf8)
        XCTAssertThrowsError(try MusicBrainzClient.parseSearchResults(garbage)) { error in
            guard case MusicBrainzError.decodingFailed = error else {
                return XCTFail("Expected .decodingFailed, got \(error)")
            }
        }
    }

    func testDetailWithoutCoverArtArchiveFieldDefaultsToFalse() throws {
        let json = Data(#"{"id":"test-id","title":"Test","date":null,"artist-credit":[{"name":"Test Artist"}],"media":[]}"#.utf8)
        let detail = try MusicBrainzClient.parseReleaseDetail(json)
        XCTAssertFalse(detail.hasCoverArt)
        XCTAssertTrue(detail.tracks.isEmpty)
    }

